const STORAGE_PREFIX = 'nccaa_';
const getKey = (key) => STORAGE_PREFIX + key;

const safeStorageGet = async (key) => {
  // 1) Inside Claude: use Claude's storage system
  try {
    if (typeof window !== 'undefined' && window.storage) {
      const result = await window.storage.get(getKey(key));
      return result ? JSON.parse(result.value) : null;
    }
  } catch (e) {
    // fall through to browser storage
  }
  // 2) On a deployed website: use the browser's localStorage
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      const raw = window.localStorage.getItem(getKey(key));
      return raw ? JSON.parse(raw) : null;
    }
  } catch (e) {
    return null;
  }
  return null;
};

const safeStorageSet = async (key, value) => {
  // 1) Inside Claude: use Claude's storage system
  try {
    if (typeof window !== 'undefined' && window.storage) {
      await window.storage.set(getKey(key), JSON.stringify(value));
      return;
    }
  } catch (e) {
    // fall through to browser storage
  }
  // 2) On a deployed website: use the browser's localStorage
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.setItem(getKey(key), JSON.stringify(value));
    }
  } catch (e) {
    // Silent fail
  }
};

const safeStorageDelete = async (key) => {
  // 1) Inside Claude: use Claude's storage system
  try {
    if (typeof window !== 'undefined' && window.storage && window.storage.delete) {
      await window.storage.delete(getKey(key));
    }
  } catch (e) {
    // fall through to browser storage
  }
  // 2) On a deployed website: use the browser's localStorage
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.removeItem(getKey(key));
    }
  } catch (e) {
    // Silent fail
  }
};

const formatDate = (timestamp) => {
  if (!timestamp) return '';
  const d = new Date(timestamp);
  return d.toLocaleDateString();
};

const daysSince = (timestamp) => {
  if (!timestamp) return Infinity;
  return Math.floor((Date.now() - timestamp) / (1000 * 60 * 60 * 24));
};

// =====================================================================
// SMART QUESTION SELECTION
// =====================================================================
const selectQuestions = (pool, history, limit) => {
  // Priority tiers per user's spec
  const wrong_overdue = [];      // Got wrong, due for review
  const wrong_recent = [];       // Got wrong, seen recently
  const never_seen = [];         // Never attempted
  const correct_old = [];        // Got right, long ago
  const correct_recent = [];     // Got right, recently

  for (const q of pool) {
    const h = history[q.id];
    if (!h) {
      never_seen.push(q);
    } else if (h.lastResult === 'wrong') {
      const days = daysSince(h.lastSeen);
      // Spaced repetition: wrong answers due after intervals based on consecutive wrongs
      const dueAfter = Math.min(7, Math.max(1, h.wrongStreak || 1));
      if (days >= dueAfter) {
        wrong_overdue.push(q);
      } else {
        wrong_recent.push(q);
      }
    } else {
      const days = daysSince(h.lastSeen);
      if (days >= 14) {
        correct_old.push(q);
      } else {
        correct_recent.push(q);
      }
    }
  }

  // Shuffle each tier
  const shuffle = (arr) => arr.sort(() => Math.random() - 0.5);
  shuffle(wrong_overdue);
  shuffle(never_seen);
  shuffle(correct_old);
  shuffle(wrong_recent);
  shuffle(correct_recent);

  // Build selection in priority order
  const selection = [
    ...wrong_overdue,
    ...never_seen,
    ...correct_old,
    ...wrong_recent,
    ...correct_recent
  ].slice(0, limit);

  return selection;
};

