const PracticeSetup = ({ setView, startSession }) => {
  const [selectedSubtopics, setSelectedSubtopics] = useState(new Set());
  const [expandedTopics, setExpandedTopics] = useState(new Set());
  const [questionCount, setQuestionCount] = useState(10);
  const [timed, setTimed] = useState(false);

  const toggleTopic = (topicId) => {
    const next = new Set(expandedTopics);
    if (next.has(topicId)) next.delete(topicId);
    else next.add(topicId);
    setExpandedTopics(next);
  };

  const toggleSubtopic = (key) => {
    const next = new Set(selectedSubtopics);
    if (next.has(key)) next.delete(key);
    else next.add(key);
    setSelectedSubtopics(next);
  };

  const selectAllInTopic = (topicId) => {
    const next = new Set(selectedSubtopics);
    const subs = Object.keys(TOPICS[topicId].subtopics);
    const allSelected = subs.every(s => next.has(`${topicId}.${s}`));
    if (allSelected) {
      subs.forEach(s => next.delete(`${topicId}.${s}`));
    } else {
      subs.forEach(s => next.add(`${topicId}.${s}`));
    }
    setSelectedSubtopics(next);
  };

  const selectAll = () => {
    const all = new Set();
    for (const [tid, t] of Object.entries(TOPICS)) {
      for (const sid of Object.keys(t.subtopics)) {
        all.add(`${tid}.${sid}`);
      }
    }
    setSelectedSubtopics(all);
  };

  const availableCount = useMemo(() => {
    if (selectedSubtopics.size === 0) return 0;
    return QUESTION_BANK.filter(q => selectedSubtopics.has(`${q.topic}.${q.subtopic}`)).length;
  }, [selectedSubtopics]);

  const handleStart = () => {
    const pool = QUESTION_BANK.filter(q => selectedSubtopics.has(`${q.topic}.${q.subtopic}`));
    if (pool.length === 0) return;
    startSession({
      pool,
      limit: Math.min(questionCount, pool.length),
      timed,
      mode: 'practice'
    });
  };

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto', padding: '40px 24px 80px' }}>
      <BackButton onClick={() => setView('home')} />
      <h1 style={{ fontFamily: 'var(--font-display)', fontSize: '40px', fontWeight: 600, letterSpacing: '-0.03em', margin: '24px 0 8px' }}>Practice Setup</h1>
      <p style={{ fontFamily: 'var(--font-body)', color: 'var(--muted)', marginBottom: '32px' }}>Select one or more subtopics. Questions you've struggled with appear first.</p>

      {/* Quick actions */}
      <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' }}>
        <GhostBtn size="sm" onClick={selectAll}>Select all topics</GhostBtn>
        <GhostBtn size="sm" onClick={() => setSelectedSubtopics(new Set())}>Clear all</GhostBtn>
      </div>

      {/* Topic tree */}
      <div style={{ background: 'var(--surface)', borderRadius: '16px', border: '1px solid var(--border)', overflow: 'hidden', marginBottom: '24px' }}>
        {Object.entries(TOPICS).map(([topicId, topic]) => {
          const isExpanded = expandedTopics.has(topicId);
          const subKeys = Object.keys(topic.subtopics);
          const selectedInTopic = subKeys.filter(s => selectedSubtopics.has(`${topicId}.${s}`)).length;
          return (
            <div key={topicId} style={{ borderBottom: '1px solid var(--border)' }}>
              <div style={{ padding: '16px 20px', display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer' }} onClick={() => toggleTopic(topicId)}>
                <div style={{ flexShrink: 0 }}>
                  {isExpanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                </div>
                <div style={{ width: '8px', height: '40px', background: topic.color, borderRadius: '4px', flexShrink: 0 }} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontFamily: 'var(--font-body)', fontWeight: 600, fontSize: '15px' }}>{topic.name}</div>
                  <div style={{ fontFamily: 'var(--font-body)', fontSize: '12px', color: 'var(--muted)' }}>
                    {topic.weight}% of exam · {selectedInTopic}/{subKeys.length} subtopics selected
                  </div>
                </div>
                <button
                  onClick={(e) => { e.stopPropagation(); selectAllInTopic(topicId); }}
                  style={{
                    background: 'transparent',
                    border: '1px solid var(--border)',
                    borderRadius: '999px',
                    padding: '4px 12px',
                    fontFamily: 'var(--font-body)',
                    fontSize: '11px',
                    cursor: 'pointer',
                    color: 'var(--ink)'
                  }}
                >
                  {selectedInTopic === subKeys.length ? 'Deselect all' : 'Select all'}
                </button>
              </div>
              {isExpanded && (
                <div style={{ padding: '0 20px 16px 58px', background: 'var(--bg)' }}>
                  {Object.entries(topic.subtopics).map(([subId, subName]) => {
                    const key = `${topicId}.${subId}`;
                    const checked = selectedSubtopics.has(key);
                    const count = QUESTION_BANK.filter(q => q.topic === topicId && q.subtopic === subId).length;
                    return (
                      <label key={subId} style={{ display: 'flex', alignItems: 'center', padding: '8px 0', cursor: 'pointer', gap: '12px' }}>
                        <input
                          type="checkbox"
                          checked={checked}
                          onChange={() => toggleSubtopic(key)}
                          style={{ accentColor: 'var(--accent)', width: '16px', height: '16px', cursor: 'pointer' }}
                        />
                        <span style={{ fontFamily: 'var(--font-body)', fontSize: '14px', color: 'var(--ink)', flex: 1 }}>{subName}</span>
                        <span style={{ fontFamily: 'var(--font-body)', fontSize: '11px', color: 'var(--muted)' }}>{count} question{count !== 1 ? 's' : ''}</span>
                      </label>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Options */}
      <div style={{ background: 'var(--surface)', borderRadius: '16px', border: '1px solid var(--border)', padding: '24px', marginBottom: '24px' }}>
        <div style={{ marginBottom: '20px' }}>
          <label style={{ fontFamily: 'var(--font-body)', fontSize: '13px', color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: '0.08em', display: 'block', marginBottom: '12px' }}>Number of questions</label>
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            {[5, 10, 20, 30, 50].map(n => (
              <button
                key={n}
                onClick={() => setQuestionCount(n)}
                style={{
                  background: questionCount === n ? 'var(--ink)' : 'transparent',
                  color: questionCount === n ? 'var(--bg)' : 'var(--ink)',
                  border: '1px solid var(--border)',
                  padding: '8px 16px',
                  borderRadius: '999px',
                  fontFamily: 'var(--font-body)',
                  fontSize: '13px',
                  cursor: 'pointer',
                  minWidth: '48px'
                }}
              >
                {n}
              </button>
            ))}
          </div>
        </div>
        <label style={{ display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer' }}>
          <input type="checkbox" checked={timed} onChange={(e) => setTimed(e.target.checked)} style={{ accentColor: 'var(--accent)', width: '16px', height: '16px' }} />
          <span style={{ fontFamily: 'var(--font-body)', fontSize: '14px' }}>Timed mode (90 seconds per question)</span>
        </label>
      </div>

      {/* Start */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '16px', flexWrap: 'wrap' }}>
        <div style={{ fontFamily: 'var(--font-body)', fontSize: '13px', color: 'var(--muted)' }}>
          {availableCount === 0 ? 'Select at least one subtopic' : `${availableCount} question${availableCount !== 1 ? 's' : ''} available · will quiz on ${Math.min(questionCount, availableCount)}`}
        </div>
        <PrimaryBtn onClick={handleStart} disabled={availableCount === 0}>
          Begin Practice →
        </PrimaryBtn>
      </div>
    </div>
  );
};

